UPDATE coaching.exercise SET
  name = 'Partner Random Bounce Catch with Balance Reset',
  description = 'Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.',
  card_summary = 'Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep.',
  coach_language = 'Primary subrole: Perception-Action Reactive Movement. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.',
  athlete_language = 'Track the bounce.',
  movement_family = 'Visual Tracking + Catching Decision',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'random_bounce_catch_balance_reset',
  default_sets = 2,
  default_reps = 5,
  default_work_seconds = 30,
  default_rest_seconds = 45,
  est_seconds_per_set = 75,
  movement_requirements = '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"breathing_demand":"controlled_rhythm","balance_demand":"dynamic","coordination_demand":"multi_stimulus_reactive","impact_level":1}'::jsonb,
  coaching_execution = '{"movement_description":"Random bounce catches force visual tracking, quick hand choice, and a clean balance reset after each rep. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Track the bounce.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"athlete_cues":["Track the bounce.","See it before you solve it.","Clean catch, clean reset."],"breathing_cues":["Breathe normally between attempts.","Use a quick brace or exhale during a cut, jump, or landing, then reset breathing before the next rep."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."],"quality_gate":["Athlete identifies the correct cue before or immediately after the catch.","Feet stay quiet enough to control the finish.","Ball is secured without bobble on most quality attempts.","The final rep looks nearly as organized as the first rep."],"stop_signs":["Pain, dizziness, headache, visual disturbance, or concussion symptoms appear.","Athlete repeatedly loses balance or enters another athlete''s space.","Catching quality drops for two reps in a row.","The athlete stops processing the cue and simply guesses."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Football skill block","Route mechanics at controlled speed","Strength or conditioning placed later if coordination quality remains high"],"pairs_well_after":["General warm-up","Movement prep for ankles, hips, and trunk","Low-pressure catch rehearsal"],"good_for_sessions":["general_warmup","sprint_prep","football_skill_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or movement changes because of pain.","Dizziness, headache, nausea, visual disturbance, or concussion symptoms are present.","The athlete cannot track the object safely or the space is not clear.","The coach is using the drill as a fatigue finisher instead of a coordination exposure."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex coordination and ball-skill demo recommended","Motor learning: low-fatigue, high-attention practice principles","Football receiver ball-tracking and situational-awareness coaching principles"],"internal_notes":["Film Partner Random Bounce Catch with Balance Reset from front/side and, when useful, from the thrower''s view.","Show the base version, one regression, and one progression.","Score coordination and perception-action skill high; do not recast this as conditioning."]}'::jsonb,
