UPDATE coaching.exercise SET
  name = 'Slant Catch Through Moving Window',
  description = 'Receiver catches a slant through a moving window created by a coach or partner while maintaining route speed. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.',
