  coach_language = 'Primary subrole: Reactive Agility Output. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.',
  athlete_language = 'Run through the window.',
  movement_family = 'Football Spatial Awareness + Catch Transfer',
  primary_phase_key = 'output',
  phase_subrole = 'reactive_agility_tumbling_output',
