  coaching_execution = '{"movement_description":"Receiver catches a slant through a moving window created by a coach or partner while maintaining route speed. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Run through the window.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"athlete_cues":["Run through the window.","See it before you solve it.","Clean catch, clean reset."],"breathing_cues":["Breathe normally between attempts.","Use a quick brace or exhale during a cut, jump, or landing, then reset breathing before the next rep."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."],"quality_gate":["Athlete identifies the correct cue before or immediately after the catch.","Feet stay quiet enough to control the finish.","Ball is secured without bobble on most quality attempts.","The final rep looks nearly as organized as the first rep."],"stop_signs":["Pain, dizziness, headache, visual disturbance, or concussion symptoms appear.","Athlete repeatedly loses balance or enters another athlete''s space.","Catching quality drops for two reps in a row.","The athlete stops processing the cue and simply guesses."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Full route or small-sided competitive skill","Lower-body strength after adequate rest","Conditioning only after output quality is complete"],"pairs_well_after":["General warm-up","Landing preparation","Low-speed version of the same decision drill"],"good_for_sessions":["sprint_prep","landing_prep","football_skill_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears or movement changes because of pain.","Dizziness, headache, nausea, visual disturbance, or concussion symptoms are present.","The athlete cannot track the object safely or the space is not clear.","The coach is using the drill as a fatigue finisher instead of a coordination exposure."]}'::jsonb,
