UPDATE coaching.exercise SET
  name = 'YAC Tuck-Cut-Scan After Catch',
  description = 'Receiver catches, tucks, cuts off a cue, and scans for the next defender or space. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.',
  card_summary = 'Receiver catches, tucks, cuts off a cue, and scans for the next defender or space.',
  coach_language = 'Primary subrole: Deceleration and Change-of-Direction Power. Coach this as a coordination drill first: accurate perception, organized feet, clean catch, and controlled reset before more speed or pressure.',
