  default_work_seconds = 15,
  default_rest_seconds = 75,
  est_seconds_per_set = 90,
  movement_requirements = '{"primary_joint_actions":["multi_directional_locomotion","hip_knee_ankle_coordination","trunk_rotation_control","hip_rotation","landing_absorption","deceleration_braking","visual_tracking","hand_eye_coordination"],"primary_tissues":["intrinsic_foot","calves","glutes","hip_stabilizers","anterior_core","shoulder_stabilizers","forearm_hand_complex","quadriceps","hamstrings","achilles_tendon"],"primary_motor_control_demands":["visual_tracking","choice_reaction","interlimb_timing","catch_timing"],"breathing_demand":"braced_exhale_on_cut_or_landing","balance_demand":"dynamic","coordination_demand":"multi_stimulus_reactive","impact_level":3,"reactive_output_profile":{"stimulus_type":"visual_or_auditory_late_cue","decision_options":"2_to_4_options","amplitude_cap":"Keep approach speed and cut angle low enough that the athlete can finish safely.","quality_trigger":"Progress only when decision accuracy and foot control stay consistent."}}'::jsonb,
  coaching_execution = '{"movement_description":"Receiver catches, tucks, cuts off a cue, and scans for the next defender or space. The goal is not random difficulty; it is coordinated seeing, deciding, moving, catching, and resetting with repeatable mechanics.","setup":["Set a safe lane or station with clear boundaries and no collision risk.","Choose one primary cue before the set: color, number, direction, partner movement, or ball flight.","Start at a speed where the athlete can see the cue, move cleanly, and catch without panic."],"execution_steps":["Athlete starts in the prescribed stance or movement pattern.","Coach or partner gives the cue late enough to require attention but early enough to keep the rep safe.","Athlete solves the cue, tracks the object, catches or handles the ball, and finishes in control.","Athlete calls what they saw after the catch, then resets before the next attempt."],"coach_cues":["Catch to runner.","Eyes quiet before hands quick.","Solve the cue first.","Catch clean, then reset.","Stop before sloppy."],"athlete_cues":["Catch to runner.","See it before you solve it.","Clean catch, clean reset."],"breathing_cues":["Breathe normally between attempts.","Use a quick brace or exhale during a cut, jump, or landing, then reset breathing before the next rep."],"common_faults":["Looking at the feet instead of the cue or ball.","Rushing the rep and guessing before the stimulus is clear.","Adding extra steps, hops, or body sway after the catch.","Catching with panic hands instead of soft hands and a stable finish.","Turning the drill into fatigue work instead of coordination practice."],"quality_gate":["Athlete identifies the correct cue before or immediately after the catch.","Feet stay quiet enough to control the finish.","Ball is secured without bobble on most quality attempts.","The final rep looks nearly as organized as the first rep."],"stop_signs":["Pain, dizziness, headache, visual disturbance, or concussion symptoms appear.","Athlete repeatedly loses balance or enters another athlete''s space.","Catching quality drops for two reps in a row.","The athlete stops processing the cue and simply guesses."]}'::jsonb,
