-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for coordination, perception-action timing, and spatial awareness under duress.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('color-call-tennis-ball-catch-on-single-leg-balance', 'Color-Call Tennis Ball Catch on Single-Leg Balance layers a clear perception task onto a controlled movement task. The athlete must coordinate eyes, feet, trunk, and hands at the same time, which is the exact problem in sport when a receiver tracks the ball while adjusting to space, pressure, and balance demands.', 'Belongs in Movement Intelligence because the primary adaptation is coordination, perception-action timing, rhythm, and spatial awareness while the nervous system is fresh. The dominant subrole is Balance, Coordination, and Rhythm.', 'Use after warm-up and before fatigue-heavy strength, conditioning, or long competitive periods. Keep reps crisp and stop before learning quality drops.', 'Do not turn this into conditioning or chaos-for-chaos'' sake. If eyes get late, feet get loud, or the athlete stops making clean decisions, the set is over. Do not progress speed, balance challenge, and decision complexity all at once.', 'Scale one variable at a time: reduce speed first, then reduce decision complexity, object size/speed, stance difficulty, distance, impact, or partner pressure. Progress only when the athlete can explain the cue, catch cleanly, and reset without extra steps.'),
  ('single-leg-football-catch-with-late-color-call', 'Single-Leg Football Catch with Late Color Call layers a clear perception task onto a controlled movement task. The athlete must coordinate eyes, feet, trunk, and hands at the same time, which is the exact problem in sport when a receiver tracks the ball while adjusting to space, pressure, and balance demands.', 'Belongs in Movement Intelligence because the primary adaptation is coordination, perception-action timing, rhythm, and spatial awareness while the nervous system is fresh. The dominant subrole is Balance, Coordination, and Rhythm.', 'Use after warm-up and before fatigue-heavy strength, conditioning, or long competitive periods. Keep reps crisp and stop before learning quality drops.', 'Do not turn this into conditioning or chaos-for-chaos'' sake. If eyes get late, feet get loud, or the athlete stops making clean decisions, the set is over. Do not progress speed, balance challenge, and decision complexity all at once.', 'Scale one variable at a time: reduce speed first, then reduce decision complexity, object size/speed, stance difficulty, distance, impact, or partner pressure. Progress only when the athlete can explain the cue, catch cleanly, and reset without extra steps.'),
  ('jog-cut-catch-scan-drill', 'Jog-Cut-Catch-Scan Drill layers a clear perception task onto a controlled movement task. The athlete must coordinate eyes, feet, trunk, and hands at the same time, which is the exact problem in sport when a receiver tracks the ball while adjusting to space, pressure, and balance demands.', 'Belongs in Movement Intelligence because the primary adaptation is coordination, perception-action timing, rhythm, and spatial awareness while the nervous system is fresh. The dominant subrole is Perception-Action Reactive Movement.', 'Use after warm-up and before fatigue-heavy strength, conditioning, or long competitive periods. Keep reps crisp and stop before learning quality drops.', 'Do not turn this into conditioning or chaos-for-chaos'' sake. If eyes get late, feet get loud, or the athlete stops making clean decisions, the set is over. Do not progress speed, balance challenge, and decision complexity all at once.', 'Scale one variable at a time: reduce speed first, then reduce decision complexity, object size/speed, stance difficulty, distance, impact, or partner pressure. Progress only when the athlete can explain the cue, catch cleanly, and reset without extra steps.'),
  ('two-ball-number-call-catch', 'Two-Ball Number Call Catch layers a clear perception task onto a controlled movement task. The athlete must coordinate eyes, feet, trunk, and hands at the same time, which is the exact problem in sport when a receiver tracks the ball while adjusting to space, pressure, and balance demands.', 'Belongs in Movement Intelligence because the primary adaptation is coordination, perception-action timing, rhythm, and spatial awareness while the nervous system is fresh. The dominant subrole is Perception-Action Reactive Movement.', 'Use after warm-up and before fatigue-heavy strength, conditioning, or long competitive periods. Keep reps crisp and stop before learning quality drops.', 'Do not turn this into conditioning or chaos-for-chaos'' sake. If eyes get late, feet get loud, or the athlete stops making clean decisions, the set is over. Do not progress speed, balance challenge, and decision complexity all at once.', 'Scale one variable at a time: reduce speed first, then reduce decision complexity, object size/speed, stance difficulty, distance, impact, or partner pressure. Progress only when the athlete can explain the cue, catch cleanly, and reset without extra steps.'),
  ('partner-random-bounce-catch-with-balance-reset', 'Partner Random Bounce Catch with Balance Reset layers a clear perception task onto a controlled movement task. The athlete must coordinate eyes, feet, trunk, and hands at the same time, which is the exact problem in sport when a receiver tracks the ball while adjusting to space, pressure, and balance demands.', 'Belongs in Movement Intelligence because the primary adaptation is coordination, perception-action timing, rhythm, and spatial awareness while the nervous system is fresh. The dominant subrole is Perception-Action Reactive Movement.', 'Use after warm-up and before fatigue-heavy strength, conditioning, or long competitive periods. Keep reps crisp and stop before learning quality drops.', 'Do not turn this into conditioning or chaos-for-chaos'' sake. If eyes get late, feet get loud, or the athlete stops making clean decisions, the set is over. Do not progress speed, balance challenge, and decision complexity all at once.', 'Scale one variable at a time: reduce speed first, then reduce decision complexity, object size/speed, stance difficulty, distance, impact, or partner pressure. Progress only when the athlete can explain the cue, catch cleanly, and reset without extra steps.'),
