-- Coordination under duress cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'coordination_under_duress_readiness',
  NULL,
  'Coordination under duress without conditioning drift or wrong phase intent',
  'Visual tracking, catch-decision, balance-integrated object control, and multi-limb timing drills must stay fresh, crisp, and coordination-first — not fatigue circuits disguised as skill work.',
  'Coordination cards span visual tracking and catching decisions, reactive movement under pressure, balance-integrated object control, whole-body rhythm, and football spatial-awareness catch transfer.',
  'Coordination under duress depends on perception-action timing, trunk control, and clean decision-making while fresh. Poor placement, short rest, or stacking speed, balance, and decision complexity at once trains sloppy catches and unsafe chaos.',
  'Place after warm-up and before fatigue-heavy strength or conditioning. Score coordination and perception-action skill high; stop sets when eyes get late, feet get loud, or catch quality drops.',
  'Do not program coordination drills after conditioning, use them as fatigue finishers, or progress speed, balance challenge, and decision complexity all at once.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
